import os
import logging
import traceback

from multiprocessing import Manager, Pool
from abc import ABC, abstractmethod
from uuid import uuid4


def error_handler(e):
    print(f"子进程错误: {str(e)}")


def create_pool_for_worker(worker):
    return Pool(processes=worker.worker_num)


class ProcessManager:
    PROC_MANAGER = None
    def init_manager():
        ProcessManager.PROC_MANAGER = Manager()


class WorkerBase(ABC):
    def __init__(self, worker_num, log_dir, mount_pool=False):
        self.logger = logging.getLogger(__name__)
        self.worker_num = worker_num
        self.log_dir = log_dir
        # 全局共享资源
        self.task_queue = ProcessManager.PROC_MANAGER.Queue()
        self.proc_results = ProcessManager.PROC_MANAGER.dict()      # 存储 {task_id: 结果}
        self.proc_notify = ProcessManager.PROC_MANAGER.dict()       # 存储 {task_id: Event}，用于阻塞通知
        if not mount_pool:
            pool = Pool(processes=worker_num)
            self.start(pool)

    def start(self, pool):
        for worker_id in range(self.worker_num):
            pool.apply_async(self.worker, args=(worker_id, self.log_dir), error_callback=error_handler)

    def worker(self, worker_id, log_dir):
        """工作进程函数，持续处理队列任务"""
        logging.basicConfig(
            filename=os.path.join(log_dir, f"worker_{str(worker_id)}.log"),   # 日志文件名
            level=logging.INFO,       # 设置最低级别为DEBUG，记录所有日志
            format='%(asctime)s - %(levelname)s - %(message)s',
            datefmt='%Y-%m-%d %H:%M:%S',
            force=True
        )
        try:
            app_service = self.init_app_service()
        except Exception as e:
            self.logger.error(f"[!] Worker {worker_id} Error initializing AppService:", str(e))
            exit(1)
        self.logger.info(f"[+] Worker {worker_id} ready.")
        while True:
            try:
                task_id, task = self.task_queue.get(block=True)
                result = self.process_task(task, worker_id, app_service)
                # 写入结果并发送完成信号
                self.proc_results[task_id] = result
                self.proc_notify[task_id].set()  # 任务完成，发唤醒信号
                # 异步后续处理：例如提交log等
                self.post_process(worker_id, result)
            except Exception as e:
                print(f"[!] Worker {worker_id} Error processing task:", str(e))
                error_traceback = traceback.format_exc()
                self.logger.error(f"Task processing failed: \n{error_traceback}")

    def submit_task(self, task):
        task_id = str(uuid4())
        event = ProcessManager.PROC_MANAGER.Event()
        self.proc_notify[task_id] = event
        self.task_queue.put([task_id, task])
        return {
            "task_id": task_id,
            "task_notify": event
        }

    def wait_result(self, task_ticket, timeout=10):
        task_id = task_ticket["task_id"]
        task_notify = task_ticket["task_notify"]
        if task_notify.wait(timeout=timeout):
            result = self.proc_results[task_id]
            task_notify.clear()
            del self.proc_results[task_id]
            del self.proc_notify[task_id]
            return result
        else:
            return None

    @abstractmethod
    def init_app_service(self):
        return

    @abstractmethod
    def post_process(self, worker_id, result):
        return

    @abstractmethod
    def process_task(self, task, worker_id, app_service):
        return

