        app_service = worker_cls_state.init_app_service()
    except Exception as e:
        logger.error(f"[!] Worker {worker_id} Error initializing AppService: {e}")
        exit(1)

    logger.info(f"[+] Worker {worker_id} ready.")

    while True:
        task_id = None
        try:
            task_id, task = task_queue.get(block=True)
            result = worker_cls_state.process_task(task, worker_id, app_service)
            # 写入结果并发送完成信号
            proc_results[task_id] = {"success": True, "data": result}
            proc_notify[task_id].set()
            # 异步后续处理：例如提交log等
            worker_cls_state.post_process(worker_id, result)
        except Exception as e:
            error_traceback = traceback.format_exc()
            logger.error(f"Task processing failed: \n{error_traceback}")
            print(f"[!] Worker {worker_id} Error processing task: {e}")
            # 即使异常也要通知调用方，避免永久阻塞
            if task_id is not None:
                try:
                    proc_results[task_id] = {"success": False, "error": str(e)}
                    proc_notify[task_id].set()
                except Exception:
                    logger.error(f"Failed to notify caller for task {task_id}")


class WorkerBase(ABC):
    def __init__(self, worker_num, log_dir, mount_pool=False):
        self.logger = logging.getLogger(__name__)
        self.worker_num = worker_num
        self.log_dir = log_dir
        # 全局共享资源
        self.task_queue = ProcessManager.PROC_MANAGER.Queue()
        self.proc_results = ProcessManager.PROC_MANAGER.dict()      # 存储 {task_id: 结果}
        self.proc_notify = ProcessManager.PROC_MANAGER.dict()       # 存储 {task_id: Event}，用于阻塞通知
        self.pool = None
        if not mount_pool:
            self.pool = Pool(processes=worker_num)
            self.start(self.pool)

    def start(self, pool):
        self.pool = pool
        for worker_id in range(self.worker_num):
            pool.apply_async(
                _worker_entry,
                args=(self, worker_id, self.log_dir, self.task_queue, self.proc_results, self.proc_notify),
                error_callback=error_handler
            )

    def submit_task(self, task):
        task_id = str(uuid4())
        event = ProcessManager.PROC_MANAGER.Event()
        self.proc_notify[task_id] = event
        self.task_queue.put([task_id, task])
        return {
            "task_id": task_id,
            "task_notify": event
        }

    def wait_result(self, task_ticket, timeout=10):
        task_id = task_ticket["task_id"]
        task_notify = task_ticket["task_notify"]
        if task_notify.wait(timeout=timeout):
            result = self.proc_results[task_id]
            task_notify.clear()
            del self.proc_results[task_id]
            del self.proc_notify[task_id]
            return result
        else:
            # 超时时清理共享资源，防止内存泄漏
            try:
                del self.proc_notify[task_id]
                # proc_results 可能还未写入，安全删除
                if task_id in self.proc_results:
                    del self.proc_results[task_id]
            except KeyError:
                pass
            return None

    def shutdown(self):
        """优雅关闭进程池"""
        if self.pool is not None:
            self.pool.terminate()
            self.pool.join()
            self.pool = None

    @abstractmethod
    def init_app_service(self):
        return

    @abstractmethod
    def post_process(self, worker_id, result):
        return

    @abstractmethod
    def process_task(self, task, worker_id, app_service):
        return

